#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e3 + 5;
const int M = 5e5 + 5;

int n, m, s, t;

int dis[N], cnt[N], a[N];
bool vis[N];

struct Edge
{
    int v, w, d;
};
vector<Edge> e[N];


void SPFA()
{
    queue<int> q;
    memset(dis, 0x3f, sizeof dis);
    memset(cnt, 0x3f, sizeof cnt);
    dis[s] = 0, vis[s] = 1, cnt[s] = 0;
    q.push(s);
    while(!q.empty())
    {
        int u = q.front();
        q.pop();
        vis[u] = 0;
        for(auto [v, w, d] : e[u])
        {
            if(dis[v] > dis[u] + w || dis[v] == dis[u] + w && cnt[v] > cnt[u] + d)
            {
                dis[v] = dis[u] + w;
                cnt[v] = cnt[u] + d;
                if(!vis[v]) q.push(v), vis[v] = 1;
            }
        }
    }
}

signed main()
{
	n = 1000;
    cin.tie(0) -> sync_with_stdio(0);
    cin >> s >> t >> m;
    for(int i = 1; i <= m; i++)
    {
        int cost, l;
        cin >> cost >> l;
        for(int j = 1; j <= l; j++)
        	cin >> a[j];
        for(int j = 1; j < l; j++)
        	for(int k = j + 1; k <= l; k++)
        	{
        		e[a[j]].push_back({a[k], cost, k - j});
        	}
    }
    SPFA();
    if(dis[t] >= 1e18 && cnt[t] >= 1e18)
    	puts("-1 -1");
    else
    	cout << dis[t] << ' ' << cnt[t];
    return 0;
}
